const r = msg.payload;
if (!r || typeof r !== 'object') { node.warn('invalid payload'); return null; }
const required = ['meter_id','voltage_v','current_a','power_w','energy_kwh'];
for (const k of required) {
    if (typeof r[k] === 'undefined') { node.warn('missing field: ' + k); return null; }
}
r.ts = r.ts || Date.now();
flow.set('latest', r);

// Append to in-memory ring buffer (cap keeps memory bounded).
const MAX = 5000;
const buf = flow.get('readings') || [];
buf.push(r);
if (buf.length > MAX) buf.splice(0, buf.length - MAX);
flow.set('readings', buf);

msg.payload = r;
return msg;

const r = msg.payload;
return [
    { topic: 'power_w',   payload: r.power_w },
    { topic: 'voltage_v', payload: r.voltage_v },
    { topic: 'current_a', payload: r.current_a }
];

const T = {
    voltage_v: { min: 210, max: 250 },
    current_a: { min: 0,   max: 30  },
    power_w:   { min: 0,   max: 6000 }
};
const r = msg.payload;
const found = [];
for (const key of Object.keys(T)) {
    const v = r[key];
    if (v < T[key].min) found.push({ metric: key, value: v, threshold: T[key].min, message: r.meter_id + ': ' + key + ' below min (' + v + ' < ' + T[key].min + ')' });
    if (v > T[key].max) found.push({ metric: key, value: v, threshold: T[key].max, message: r.meter_id + ': ' + key + ' above max (' + v + ' > ' + T[key].max + ')' });
}
if (!found.length) return null;

// Persist alerts in flow context (ring buffer).
const MAX = 500;
const store = flow.get('alerts') || [];
for (const a of found) store.push({ meter_id: r.meter_id, ts: r.ts, ...a });
if (store.length > MAX) store.splice(0, store.length - MAX);
flow.set('alerts', store);

return found.map(a => ({ payload: a.message }));

const TARIFF = 0.15; // cost per kWh (edit to match your tariff)
const readings = flow.get('readings') || [];
const latest   = flow.get('latest')   || null;
const alerts   = flow.get('alerts')   || [];
const now = Date.now();

const dayStart = new Date(); dayStart.setHours(0,0,0,0);
const kwhSince = (sinceTs) => {
    const slice = readings.filter(x => x.ts >= sinceTs);
    if (slice.length < 2) return 0;
    return Math.max(0, slice[slice.length-1].energy_kwh - slice[0].energy_kwh);
};
const today = kwhSince(dayStart.getTime());
const week  = kwhSince(now - 7*86400000);
const month = kwhSince(now - 30*86400000);
const alert_count_24h = alerts.filter(a => a.ts > now - 86400000).length;

msg.payload = {
    current: latest,
    today_kwh: +today.toFixed(3),
    week_kwh:  +week.toFixed(3),
    month_kwh: +month.toFixed(3),
    today_cost: +(today*TARIFF).toFixed(2),
    week_cost:  +(week*TARIFF).toFixed(2),
    month_cost: +(month*TARIFF).toFixed(2),
    tariff_per_kwh: TARIFF,
    alert_count_24h
};
msg.headers = { 'Content-Type': 'application/json' };
return msg;

const hours = Math.min(24, Math.max(1, parseInt((msg.req && msg.req.query && msg.req.query.hours) || '1', 10)));
const since = Date.now() - hours*3600000;
const rows = (flow.get('readings') || [])
    .filter(r => r.ts >= since)
    .map(r => ({ ts: r.ts, voltage_v: r.voltage_v, current_a: r.current_a, power_w: r.power_w }));
const max = 120;
let out = rows;
if (rows.length > max) {
    const step = Math.ceil(rows.length / max);
    out = rows.filter((_, i) => i % step === 0);
}
msg.payload = out;
msg.headers = { 'Content-Type': 'application/json' };
return msg;

const limit = Math.min(100, Math.max(1, parseInt((msg.req && msg.req.query && msg.req.query.limit) || '10', 10)));
const alerts = flow.get('alerts') || [];
msg.payload = alerts.slice(-limit).reverse().map(a => ({
    ts: a.ts, metric: a.metric, value: a.value, threshold: a.threshold, message: a.message
}));
msg.headers = { 'Content-Type': 'application/json' };
return msg;
